// RAG-enhanced system prompt builder
async function buildRAGSystemPrompt(userQuery: string, userId?: string, searchMode?: string): Promise<{ prompt: string; sources: Source[]; youtubeVideos: any[] }> {
  let ragContext = '';
  let sources: Source[] = [];
  let youtubeVideos: any[] = [];
  
  try {
    // Generate embedding for the query
    const queryEmbedding = await generateEmbeddingWithRetry(userQuery);
    
    // Search knowledge base (always do this)
    const knowledgeResults = await searchKnowledge(queryEmbedding, 3);
    
    if (knowledgeResults.length > 0) {
      sources = knowledgeResults.map((result, idx) => ({
        id: idx + 1,
        title: result.title,
        url: result.source || '',
        type: 'qdrant' as const,
        snippet: result.content.slice(0, 200),
      }));
      
      ragContext += '\n\n### RELEVANT KNOWLEDGE (with citations)\n';
      knowledgeResults.forEach((result, idx) => {
        // Use parent content for more context, fallback to child content
        const contextText = result.parentContent || result.content;
        ragContext += `[${idx + 1}] ${result.title}${result.source ? ` [Source: ${result.source}]` : ''}:\n${contextText}\n\n`;
      });
      
      // Add citation instruction
      ragContext += '\n### CITATION INSTRUCTION\n';
      ragContext += 'When you use information from the sources above, cite them with [1], [2], etc. at the end of the relevant sentence.\n';
    }
    
    // DEEP SEARCH: DuckDuckGo web search
    if (searchMode === 'deep-search') {
      console.log('🔍 Deep search: Searching DuckDuckGo...');
      try {
        const searchResponse = await fetch('http://localhost:3000/api/search', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ query: userQuery }),
        });
        
        if (searchResponse.ok) {
          const searchData = await searchResponse.json();
          const webResults = searchData.results || [];
          
          if (webResults.length > 0) {
            // Add web sources to the list
            const webStartIdx = sources.length;
            webResults.slice(0, 5).forEach((result: any, idx: number) => {
              sources.push({
                id: webStartIdx + idx + 1,
                title: result.title,
                url: result.url,
                type: 'web' as const,
                snippet: result.snippet?.slice(0, 200) || '',
              });
            });
            
            ragContext += '\n\n### RELEVANT WEB RESULTS\n';
            webResults.slice(0, 5).forEach((result: any, idx: number) => {
              const sourceNum = webStartIdx + idx + 1;
              ragContext += `[${sourceNum}] ${result.title} [Source: ${result.source}]:\n${result.snippet}\n\n`;
            });
          }
        }
      } catch (error) {
        console.error('DuckDuckGo search error:', error);
      }
    }
    
    // Search user facts for personalization if userId provided
    if (userId) {
      const userFacts = await searchUserFacts(userId, queryEmbedding, 3);
      if (userFacts.length > 0) {
        ragContext += '\n\n### USER PREFERENCES\n';
        userFacts.forEach((fact) => {
          ragContext += `- ${fact.fact}\n`;
        });
      }
      
      // Search chat history for long-term memory
      const chatHistory = await searchChatHistory(userId, queryEmbedding, 5);
      if (chatHistory.length > 0) {
        ragContext += '\n\n### RELEVANT PAST CONVERSATIONS\n';
        chatHistory.slice(0, 3).forEach((msg, idx) => {
          ragContext += `[${idx + 1}] ${msg.role === 'user' ? 'User' : 'Assistant'}: ${msg.content.substring(0, 200)}...\n`;
        });
      }
    }
    
  } catch (error) {
    console.error('RAG retrieval error:', error);
  }
  
  return { prompt: SYSTEM_PROMPT + ragContext, sources, youtubeVideos };
}

export async function POST(req: Request) {
  const { messages, model, userId, searchMode } = await req.json();
  
  // Get the latest user message for RAG
  const latestMessage = messages[messages.length - 1];
  const userQuery = latestMessage?.content || '';

  // Build RAG-enhanced system prompt and get metadata
  const { prompt: enhancedSystemPrompt, sources, youtubeVideos } = await buildRAGSystemPrompt(userQuery, userId, searchMode);

  // Create a stream that includes metadata first, then the AI response
  const stream = new ReadableStream({
    async start(controller) {
      // Send metadata as first chunk
      const metadata = JSON.stringify({ type: 'metadata', sources, youtubeVideos });
      controller.enqueue(new TextEncoder().encode(metadata + '\n'));
      
      try {
        let result;
        
        // DUAL-AGENT WORKFLOW: If user selected medium, use fast for thinking, slow for generation
        if (model === 'medium') {
          console.log('🧠 Dual-agent: Fast agent thinking, slow agent generating...');
          
          // Step 1: Fast agent generates a plan/thinking
          const thinkingResult = await streamText({
            model: groqProvider.languageModel('llama-3.1-8b-instant'),
            system: enhancedSystemPrompt,
            messages: [...messages, {
              role: 'user',
              content: 'Generate a brief plan/approach for answering this. Keep it under 100 words.'
            }],
          });
          
          let thinkingText = '';
          for await (const chunk of thinkingResult.textStream) {
            thinkingText += chunk;
          }
          
          console.log('📝 Plan generated, now using slow agent to respond...');
          
          // Step 2: Use slow agent (nyati) with optimized settings for generation
          result = await streamText({
            model: nyatiCore.languageModel('llama3.2:1b'),
            system: enhancedSystemPrompt + '\n\n### GENERATION GUIDELINES\nRespond quickly and concisely. Use the following plan to guide your response:\n' + thinkingText,
            messages,
            temperature: 0.7,
          });
        } else if (model === 'groq' || model === 'pro') {
          // Fast agent only (Koda-A)
          console.log('Using Groq API (fast)...');
          result = await streamText({
            model: groqProvider.languageModel('llama-3.1-8b-instant'),
            system: enhancedSystemPrompt,
            messages,
          });
        } else {
          // Slow agent only (nyati-core)
          console.log('Using HF API (nyati slow)...');
          result = await streamText({
            model: nyatiCore.languageModel('llama3.2:1b'),
            system: enhancedSystemPrompt,
            messages,
            temperature: 0.7,
          });
        }
        
        // Stream the text chunks
        for await (const chunk of result.textStream) {
          try {
            controller.enqueue(new TextEncoder().encode(chunk));
          } catch (enqueueError) {
            // Controller may be closed, break the loop
            break;
          }
        }
        
        try {
          controller.close();
        } catch (closeError) {
          // Controller already closed, ignore
        }
      } catch (error) {
        console.error('Streaming error:', error);
        controller.error(error);
      }
    }
  });

  return new Response(stream, {
    headers: { 'Content-Type': 'text/plain; charset=utf-8' },
  });
}
